import { useNavigate } from "react-router-dom";
import Logo from "../assets/favicon.svg";

const NotFound = () => {
  const navigate = useNavigate();
  return (
    <div
      className="w-screen min-h-screen flex justify-center items-center p-4 cursor-pointer"
      onClick={() => navigate("/")}
    >
      <div className="relative w-full max-w-4xl bg-lime-500 shadow-[0_0_50px_0px_rgba(26,46,5,0.5)] overflow-hidden mx-auto rounded-lg aspect-video min-h-[300px] flex transition-all">
        {/* Large 404 text - responsive sizing */}
        <h1 className="text-white/20 text-[20vw] sm:text-[15vw] md:text-[12vw] lg:text-[410px] font-sans font-bold absolute -top-[10vw] sm:-top-[8vw] md:-top-[6vw] lg:-top-[168px] left-0">
          404
        </h1>

        {/* Content section - responsive positioning */}
        <div className="absolute inset-0 pl-0 sm:pl-[30vw] md:pl-[35vw] lg:pl-[400px] w-full h-full bg-black/20 rounded-lg flex flex-col justify-center items-start p-6 sm:p-8 md:p-10">
          {/* Gradient circle - responsive sizing */}
          <span className="absolute -top-[30vw] -left-[15vw] sm:-top-[25vw] sm:-left-[10vw] md:-top-[20vw] md:-left-[5vw] lg:-top-48 lg:left-0 w-[70vw] h-[70vw] sm:w-[50vw] sm:h-[50vw] md:w-[40vw] md:h-[40vw] lg:w-[350px] lg:h-[350px] rounded-full bg-gradient-to-b from-black via-black to-black/30"></span>

          {/* Logo - responsive sizing */}
          <div className="relative w-[40vw] h-[40vw] sm:w-[30vw] sm:h-[30vw] md:w-[25vw] md:h-[25vw] lg:w-[250px] lg:h-[250px] shadow-[0_0_20px_0px_#000000] rounded-full mb-4 sm:mb-6 md:mb-8 lg:mb-10 lg:left-16">
            <img
              src={Logo}
              className="w-full h-full object-contain scale-[1.01]"
              alt="Logo"
            />
          </div>

          {/* Text content - responsive sizing */}
          <p className="text-[10vw] sm:text-[8vw] md:text-[6vw] lg:text-[100px] font-black text-white mb-2 sm:mb-4 md:mb-6 lg:mb-8 leading-none">
            Oops!
          </p>
          <p className="text-[4vw] sm:text-[3vw] md:text-[2vw] lg:text-[20px] font-black text-white/50 mb-6 sm:mb-8 md:mb-10 lg:mb-14 leading-tight">
            Sorry, the page you visited does not exist.
          </p>
        </div>

        {/* Bottom right text - responsive positioning */}
        <div className="absolute bottom-4 right-4 sm:bottom-6 sm:right-6 md:bottom-8 md:right-8 lg:bottom-10 lg:right-28 flex justify-center items-start">
          <p className="z-10 text-[4vw] sm:text-[3vw] md:text-[2vw] lg:text-[22px] font-black text-white/60 mt-4 sm:mt-6 md:mt-8 lg:mt-10">
            Page Not Found!
          </p>
          <span className="absolute w-[40vw] h-[40vw] sm:w-[30vw] sm:h-[30vw] md:w-[25vw] md:h-[25vw] lg:w-[250px] lg:h-[250px] rounded-full bg-gradient-to-t from-black via-black to-black/30 -right-[15vw] -bottom-[15vw] sm:-right-[10vw] sm:-bottom-[10vw] md:-right-[5vw] md:-bottom-[5vw] lg:right-0 lg:bottom-0"></span>
        </div>
      </div>
    </div>
  );
};

export default NotFound;
